import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deepview Analytics","description":"","frontmatter":{"title":"Deepview Analytics","slug":"deepview-analytics"},"headers":[],"relativePath":"marketer-hub/deepview-analytics.md","filePath":"marketer-hub/deepview-analytics.md"}'),s={name:"marketer-hub/deepview-analytics.md"};function o(n,e,l,c,p,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="deepview-analytics" tabindex="-1">Deepview Analytics <a class="header-anchor" href="#deepview-analytics" aria-label="Permalink to &quot;Deepview Analytics&quot;">​</a></h2><p>Branch lets you track the flow of users through Deepviews. You can find this information on the <a href="https://dashboard.branch.io/configuration/deepview-activity" target="_blank" rel="noreferrer">Deepview Activity page</a> of the Branch Dashboard.</p><p>There are various metrics to understand when deep linking from your mobile website with Deepviews.</p><ul><li><strong>Views:</strong> a user viewed the mobile site.</li><li><strong>Clicks:</strong> a user clicked on the Deepview CTA</li><li><strong>Installs:</strong> a user installed the app for the first time</li><li><strong>Upgrades:</strong> a user re-opened or upgraded the app from a previous version</li></ul><p>Only users who do not have the app will go through this flow. You can view the total counts and conversion rate from each step on this chart.</p><div class="warning custom-block"><p class="custom-block-title">No Deepview CTA Click</p><p>If a user without your app clicks a Branch Link with an Active Deepview enabled but does not click the Deepview CTA, downstream activity (e.g. installs, purchases) will not be attributed to the original link click.</p></div>',6)])])}const v=t(s,[["render",o]]);export{u as __pageData,v as default};
